SELECT SEQ_RESERVATION.NEXTVAL FROM DUAL
INSERT INTO RESERVATION ( reservation_id, reservation_code, member_no, room_type_id, payment_id, checkin_date, checkout_date, guest_count, total_price, reservation_status, created_at, cancel_deadline, refund_amount
, fk_promotion_id
) VALUES ( #{reservation_id}, 'R' || TO_CHAR(SYSDATE,'YYYYMMDD') || '-' || LPAD(#{reservation_id},4,'0'), #{member_no}, #{room_type_id}, #{payment_id}, TO_DATE(#{check_in}, 'YYYY-MM-DD'), TO_DATE(#{check_out}, 'YYYY-MM-DD'), #{guest_count}, #{total_price}, 'CONFIRMED', SYSDATE, #{cancel_deadline}, #{refund_amount}
, #{promotion_id}
)
